UPDATE ORDER_DETAIL
SET order_detail_state = '20'
WHERE order_detail_no = #{order_detail_no}



UPDATE GOODS_ATTRIBUTE
SET goods_att_amount = goods_att_amount + #{order_detail_amount}
WHERE goods_att_no = #{old_goods_att_no}



